492	+//! `SYS_GETINFO` — kernel-state introspection.
493	+//!
494	+//! The request sub-type lives in the first 4 bytes of the message payload
495	+//! (mirrors MINIX 3 `mess_lsys_krn_sys_getinfo.request`). Phase 2 implements
496	+//! only `GET_WHOAMI`; every other sub-type returns `EINVAL` so a stub that
497	+//! sends an unsupported request gets a recognizable error rather than a
498	+//! silently-zeroed reply.
499	+
500	+use minix4_kernel_shared::callnr::{GET_WHOAMI, SYS_GETINFO_NAME_LEN};
501	+use minix4_kernel_shared::error::{EINVAL, OK};
502	+use minix4_kernel_shared::message::Message;
503	+
504	+use crate::proc::proc_struct::PROC_NAME_LEN;
505	+use crate::proc::{Priv, Proc};
506	+
507	+// The GET_WHOAMI reply embeds `caller.name` verbatim, so the kernel's
508	+// per-slot name field and the wire-format name field must stay the same
509	+// size. If `PROC_NAME_LEN` ever changes, update `SYS_GETINFO_NAME_LEN`
510	+// (and the layout-table comment below) to match.
511	+const _: () = assert!(PROC_NAME_LEN == SYS_GETINFO_NAME_LEN);
512	+
513	+/// `SYS_GETINFO` entry point. Dispatches by request sub-type.
514	+pub(super) fn do_getinfo(
515	+    caller: &mut Proc,
516	+    caller_priv: &Priv,
517	+    msg: &mut Message,
518	+) -> i32 {
519	+    let request = i32::from_ne_bytes(
520	+        msg.payload[0..4].try_into().expect("payload is at least 4 bytes"),
521	+    );
522	+    match request {
523	+        GET_WHOAMI => fill_whoami(caller, caller_priv, msg),
524	+        _ => EINVAL,
525	+    }
526	+}
527	+
528	+/// `GET_WHOAMI` reply — fills `msg.payload` in-place. Layout:
529	+///
530	+/// | offset  | type     | meaning                            |
531	+/// |---------|----------|------------------------------------|
532	+/// |   0..4  | i32      | caller endpoint                    |
533	+/// |   4..8  | i32      | `Priv::flags`, zero-extended       |
534	+/// |   8..12 | i32      | init flags (always 0 for Phase 2)  |
535	+/// |  12..28 | [u8; 16] | `Proc::name`, NUL-padded           |
536	+fn fill_whoami(caller: &Proc, caller_priv: &Priv, msg: &mut Message) -> i32 {
537	+    msg.payload[0..4].copy_from_slice(&caller.endpoint.to_ne_bytes());
538	+    msg.payload[4..8].copy_from_slice(&(caller_priv.flags as i32).to_ne_bytes());
539	+    msg.payload[8..12].copy_from_slice(&0_i32.to_ne_bytes());
540	+    msg.payload[12..12 + PROC_NAME_LEN].copy_from_slice(&caller.name);
541	+    OK
542	+}
