576	+    SYS_EXEC, SYS_EXIT, SYS_FORK, SYS_GETINFO, SYS_IRQCTL, SYS_PRIVCTL,
577	+    SYS_SAFECOPY, SYS_SCHEDULE, SYS_SETALARM, SYS_SETGRANT, SYS_TIMES, SYS_VMCTL,
578	+};
579	+use minix4_kernel_shared::com::{NR_SYS_PROCS, SYSTEM, boot_endpoint};
580	+use minix4_kernel_shared::endpoint::Endpoint;
581	+use minix4_kernel_shared::error::{EBADREQUEST, ECALLDENIED, OK};
582	+use minix4_kernel_shared::message::Message;
