599	+const KCALL_TRACE_EVERY: u64 = 100;
600	+/// Running total of kernel calls dispatched, sampled by the trace.
601	+static CALL_COUNT: AtomicU64 = AtomicU64::new(0);
602	+
603	+/// `SENDREC`-to-SYSTEM fast path.
604	+///
605	+/// Reads the request out of `user_msg_va`, runs the dispatcher, and writes
606	+/// the reply (m_source = SYSTEM, m_type = result, possibly mutated payload)
607	+/// back to the same buffer. The caller stays runnable and `el1_svc_tail`
608	+/// resumes it on return.
609	+///
610	+/// Returns the IPC-layer result (`OK`, `EFAULT`, `ECALLDENIED`); the
611	+/// kernel-call result code is carried in the reply's `m_type` field.
612	+pub fn kernel_call_sendrec(
613	+    proc_table: &mut [Proc; N_PROC_SLOTS],
614	+    priv_table: &mut [Priv; NR_SYS_PROCS],
615	+    caller_nr: ProcNr,
616	+    user_msg_va: u64,
617	+) -> i32 {
618	+    let Some(caller_idx) = proc_index(caller_nr) else {
619	+        return ECALLDENIED;
620	+    };
621	+    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
622	+        return ECALLDENIED;
623	+    };
624	+
625	+    // Apply the same ipc_to permission check that `mini_send` does
626	+    // (`ipc/send.rs:59`) — the SYSTEM endpoint isn't a special trust
627	+    // boundary, just a routing shortcut, so a caller without SYSTEM in its
628	+    // ipc_to bitmap must still be denied here.
629	+    let Some(system_idx) = proc_index(SYSTEM) else {
630	+        return ECALLDENIED;
631	+    };
632	+    let Some(system_priv_id) = proc_table[system_idx].priv_id else {
633	+        return ECALLDENIED;
634	+    };
635	+    if !get_sys_bit(
636	+        &priv_table[caller_priv_id.as_usize()].ipc_to,
637	+        system_priv_id,
638	+    ) {
639	+        return ECALLDENIED;
640	+    }
641	+
642	+    let mut msg = match copy_msg_from_user(user_msg_va) {
643	+        Ok(m) => m,
644	+        Err(e) => return e,
645	+    };
646	+    let original_m_type = msg.m_type;
647	+
648	+    // Stamp m_source so handlers see the verified caller endpoint rather
649	+    // than whatever the user scribbled into the request.
650	+    msg.m_source = proc_table[caller_idx].endpoint;
651	+
652	+    // Dispatch. proc_table and priv_table are disjoint statics, so
653	+    // borrowing one slot in each is permitted.
654	+    let result = {
655	+        let caller = &mut proc_table[caller_idx];
656	+        let caller_priv = &priv_table[caller_priv_id.as_usize()];
657	+        kernel_call_dispatch(caller, caller_priv, &mut msg)
658	+    };
659	+
660	+    // Build the reply.
661	+    msg.m_source = system_endpoint();
662	+    msg.m_type = result;
663	+    if let Err(e) = copy_msg_to_user(user_msg_va, &msg) {
664	+        return e;
665	+    }
666	+
667	+    let n = CALL_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
668	+    if n % KCALL_TRACE_EVERY == 0 {
669	+        let call_idx = original_m_type - KERNEL_CALL;
670	+        let mut uart = Uart::new();
671	+        let _ = writeln!(
672	+            uart,
673	+            "[ksys {n}] caller={caller_nr} call={call_idx} result={result}",
674	+        );
675	+    }
676	+
677	+    OK
678	+}
679	+
680	+/// Per-call dispatcher.
681	+///
682	+/// Steps: range-check `m_type - KERNEL_CALL`, gate against
683	+/// `Priv::k_call_mask`, then match on `m_type` to invoke the handler. Returns
684	+/// the result code that becomes the reply's `m_type`.
685	+fn kernel_call_dispatch(
686	+    caller: &mut Proc,
687	+    caller_priv: &Priv,
688	+    msg: &mut Message,
689	+) -> i32 {
690	+    let call_idx = msg.m_type - KERNEL_CALL;
691	+    if call_idx < 0 || (call_idx as usize) >= NR_SYS_CALLS {
692	+        return EBADREQUEST;
693	+    }
694	+    let call_idx = call_idx as usize;
695	+
696	+    let chunk = caller_priv.k_call_mask[call_idx / 32];
697	+    if chunk & (1u32 << (call_idx % 32)) == 0 {
698	+        return ECALLDENIED;
699	+    }
700	+
701	+    // Match must cover every SYS_* defined in callnr.rs. The const assert
702	+    // locks the arm count — adding a new SYS_* without a new arm here is a
703	+    // compile error.
704	+    const _: () = assert!(
705	+        NR_KERN_CALLS_PHASE2 == 14,
706	+        "expand kernel_call_dispatch when a new SYS_* lands",
707	+    );
708	+    match msg.m_type {
709	+        SYS_GETINFO => do_getinfo::do_getinfo(caller, caller_priv, msg),
710	+        SYS_PRIVCTL => stubs::do_privctl(caller, caller_priv, msg),
711	+        SYS_FORK => stubs::do_fork(caller, caller_priv, msg),
712	+        SYS_EXEC => stubs::do_exec(caller, caller_priv, msg),
713	+        SYS_EXIT => stubs::do_exit(caller, caller_priv, msg),
714	+        SYS_COPY => stubs::do_copy(caller, caller_priv, msg),
715	+        SYS_SAFECOPY => stubs::do_safecopy(caller, caller_priv, msg),
716	+        SYS_IRQCTL => stubs::do_irqctl(caller, caller_priv, msg),
717	+        SYS_VMCTL => stubs::do_vmctl(caller, caller_priv, msg),
718	+        SYS_SCHEDULE => stubs::do_schedule(caller, caller_priv, msg),
719	+        SYS_SETALARM => stubs::do_setalarm(caller, caller_priv, msg),
720	+        SYS_TIMES => stubs::do_times(caller, caller_priv, msg),
721	+        SYS_DIAGCTL => stubs::do_diagctl(caller, caller_priv, msg),
722	+        SYS_SETGRANT => stubs::do_setgrant(caller, caller_priv, msg),
723	+        _ => EBADREQUEST,
724	+    }
725	+}
