/// Test bit `id` in a sysproc-indexed bitmap.
#[inline]
pub(crate) fn get_sys_bit(map: &[u32], id: PrivId) -> bool {
    let n = id.as_usize();
    if n / 32 >= map.len() {
        return false;
    }
    map[n / 32] & (1 << (n % 32)) != 0
}

