1	//! Kernel-call dispatch — the `SYSTEM` task's role.
2	//!
3	//! In MINIX 3, `SYSTEM` is a kernel pseudo-task: it has a proc-table slot but
4	//! no scheduler context. When a server `SENDREC`s the `SYSTEM` endpoint, the
5	//! IPC fast path in `proc.c::do_ipc` short-circuits into `kernel_call()`
6	//! (`kernel/system.c`), which runs synchronously in the *caller's* EL1 stack
7	//! and writes the reply back into the caller's user buffer. The caller never
8	//! actually blocks on a receiver; SYSTEM's `IMAGE` entry exists only so that
9	//! the endpoint encodes to a valid `ProcNr`.
10	//!
11	//! MINIX 4 inherits exactly that shape. [`ipc::dispatch`] detects
12	//! `src_dst_e == boot_endpoint(SYSTEM)` in the SENDREC arm and diverts here
13	//! instead of calling [`ipc::send::mini_send`]; the rest of the IPC engine is
14	//! untouched.
15	//!
16	//! [`ipc::dispatch`]: crate::ipc
17	//! [`ipc::send::mini_send`]: crate::ipc
18	
19	mod do_getinfo;
20	mod stubs;
21	
22	use core::fmt::Write;
23	use core::sync::atomic::{AtomicU64, Ordering};
24	
25	use minix4_kernel_shared::ProcNr;
26	use minix4_kernel_shared::callnr::{
27	    KERNEL_CALL, NR_KERN_CALLS_PHASE2, NR_SYS_CALLS, SYS_COPY, SYS_DIAGCTL,
28	    SYS_EXEC, SYS_EXIT, SYS_FORK, SYS_GETINFO, SYS_IRQCTL, SYS_PRIVCTL,
29	    SYS_SAFECOPY, SYS_SCHEDULE, SYS_SETALARM, SYS_SETGRANT, SYS_TIMES, SYS_VMCTL,
30	};
31	use minix4_kernel_shared::com::{NR_SYS_PROCS, SYSTEM, boot_endpoint};
32	use minix4_kernel_shared::endpoint::Endpoint;
33	use minix4_kernel_shared::error::{EBADREQUEST, ECALLDENIED, OK};
34	use minix4_kernel_shared::message::Message;
35	
36	use crate::ipc::{copy_msg_from_user, copy_msg_to_user, get_sys_bit};
37	use crate::proc::table::{N_PROC_SLOTS, proc_index};
38	use crate::proc::{Priv, Proc};
39	use crate::uart::Uart;
40	
41	/// Boot-time endpoint of the `SYSTEM` kernel task. Generation never bumps for
42	/// kernel tasks in Phase 2 — they are statically slotted at boot and never
43	/// exit — so this single constant identifies SYSTEM for the entire kernel
44	/// lifetime.
45	#[inline]
46	pub fn system_endpoint() -> Endpoint {
47	    boot_endpoint(SYSTEM)
48	}
49	
50	/// Cadence of the boot-time kernel-call trace. Mirrors `ipc::TRACE_EVERY`.
51	const KCALL_TRACE_EVERY: u64 = 100;
52	/// Running total of kernel calls dispatched, sampled by the trace.
53	static CALL_COUNT: AtomicU64 = AtomicU64::new(0);
54	
55	/// `SENDREC`-to-SYSTEM fast path.
56	///
57	/// Reads the request out of `user_msg_va`, runs the dispatcher, and writes
58	/// the reply (m_source = SYSTEM, m_type = result, possibly mutated payload)
59	/// back to the same buffer. The caller stays runnable and `el1_svc_tail`
60	/// resumes it on return.
61	///
62	/// Returns the IPC-layer result (`OK`, `EFAULT`, `ECALLDENIED`); the
63	/// kernel-call result code is carried in the reply's `m_type` field.
64	pub fn kernel_call_sendrec(
65	    proc_table: &mut [Proc; N_PROC_SLOTS],
66	    priv_table: &mut [Priv; NR_SYS_PROCS],
67	    caller_nr: ProcNr,
68	    user_msg_va: u64,
69	) -> i32 {
70	    let Some(caller_idx) = proc_index(caller_nr) else {
71	        return ECALLDENIED;
72	    };
73	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
74	        return ECALLDENIED;
75	    };
76	
77	    // Apply the same ipc_to permission check that `mini_send` does
78	    // (`ipc/send.rs:59`) — the SYSTEM endpoint isn't a special trust
79	    // boundary, just a routing shortcut, so a caller without SYSTEM in its
80	    // ipc_to bitmap must still be denied here.
81	    let Some(system_idx) = proc_index(SYSTEM) else {
82	        return ECALLDENIED;
83	    };
84	    let Some(system_priv_id) = proc_table[system_idx].priv_id else {
85	        return ECALLDENIED;
86	    };
87	    if !get_sys_bit(
88	        &priv_table[caller_priv_id.as_usize()].ipc_to,
89	        system_priv_id,
90	    ) {
91	        return ECALLDENIED;
92	    }
93	
94	    let mut msg = match copy_msg_from_user(user_msg_va) {
95	        Ok(m) => m,
96	        Err(e) => return e,
97	    };
98	    let original_m_type = msg.m_type;
99	
100	    // Stamp m_source so handlers see the verified caller endpoint rather
101	    // than whatever the user scribbled into the request.
102	    msg.m_source = proc_table[caller_idx].endpoint;
103	
104	    // Dispatch. proc_table and priv_table are disjoint statics, so
105	    // borrowing one slot in each is permitted.
106	    let result = {
107	        let caller = &mut proc_table[caller_idx];
108	        let caller_priv = &priv_table[caller_priv_id.as_usize()];
109	        kernel_call_dispatch(caller, caller_priv, &mut msg)
110	    };
