    pr.ipc_to[sys / 32] |= 1u32 << (sys % 32);
    pr.k_call_mask.fill(0);
    let call_bit = (SYS_GETINFO - KERNEL_CALL) as usize;
    pr.k_call_mask[call_bit / 32] |= 1u32 << (call_bit % 32);
