}

fn populate_stub_slot(
    p: &mut Proc,
    nr: ProcNr,
    priv_id: PrivId,
    id: u8,
    entry_va: u64,
    stack_top: u64,
) {
    // Name: `id` followed by "stub\0..." padding. Lets the clock tick
    // handler print `name[0]` to identify which stub is running, while
    // `dump_tables` shows a recognizable per-stub string.
    p.name = [0; 16];
